    70→    {
    71→        _user_options.timeout = timeout;
    72→    }
    73→
    74→    int64 Timeout() const
    75→    {
    76→        return _user_options.timeout > 0 ?
    77→            _user_options.timeout : _auto_options.timeout;
    78→    }
